import {
  collection,
  addDoc,
  query,
  where,
  orderBy,
  getDocs,
  doc,
  getDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  Timestamp,
  onSnapshot,
} from 'firebase/firestore';
import { db, auth } from './firebase';
import { uploadImageToImgBB } from './imgbb';

export interface Message {
  id: string;
  sender: string;
  senderName: string;
  text?: string;
  photoUrl?: string;
  timestamp: number;
  type: 'text' | 'sticker' | 'voice' | 'call' | 'photo';
  stickerId?: string;
  voiceData?: { duration: number; url: string };
  callDuration?: number;
  reactions?: { [emoji: string]: string[] };
  isEdited?: boolean;
  editedAt?: number;
  isRead?: boolean;
  readAt?: number;
  replyTo?: {
    messageId: string;
    senderName: string;
    text: string;
  };
  isFavorite?: boolean;
  isPinned?: boolean;
}

export interface Chat {
  id: string;
  name: string;
  type: 'private' | 'group' | 'channel' | 'favorites';
  createdAt: number;
  members: string[];
  messages: Message[];
  avatarUrl?: string;
}

export const createChat = async (
  chatName: string,
  chatType: 'private' | 'group' | 'channel',
  members: string[]
) => {
  try {
    const chatRef = await addDoc(collection(db, 'chats'), {
      name: chatName,
      is_group: chatType !== 'private',
      type: chatType,
      created_at: Timestamp.now(),
      members,
    });
    return chatRef.id;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const sendMessage = async (
  chatId: string,
  sender: string,
  senderName: string,
  text: string,
  replyTo?: { messageId: string; senderName: string; text: string }
) => {
  try {
    const messageRef = await addDoc(collection(db, 'messages'), {
      chat_id: chatId,
      user_id: sender,
      content: text,
      message_type: 'text',
      created_at: Timestamp.now(),
    });

    if (replyTo) {
      await addDoc(collection(db, 'message_replies'), {
        message_id: messageRef.id,
        reply_to_message_id: replyTo.messageId,
      });
    }

    return messageRef;
  } catch (error: any) {
    console.error('Send message exception:', error);
    throw new Error(error.message || 'Ошибка отправки сообщения');
  }
};

export const getMessages = async (chatId: string): Promise<Message[]> => {
  try {
    const messagesRef = collection(db, 'messages');
    const q = query(messagesRef, where('chat_id', '==', chatId), orderBy('created_at', 'asc'));
    const querySnapshot = await getDocs(q);

    if (querySnapshot.empty) return [];

    const messagesData = querySnapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));

    // Получаем информацию об авторах (кэшируем)
    const userIds = [...new Set(messagesData.map((m: any) => m.user_id))];
    const usersMap = new Map<string, string>();

    for (const userId of userIds) {
      try {
        const userDoc = await getDoc(doc(db, 'users', userId));
        if (userDoc.exists()) {
          usersMap.set(userId, userDoc.data().username);
        }
      } catch (e) {
        usersMap.set(userId, 'Unknown');
      }
    }

    // Получаем избранные сообщения текущего пользователя
    const currentUser = auth.currentUser;
    let favoritesSet = new Set<string>();
    if (currentUser) {
      try {
        const favoritesRef = collection(db, 'favorites');
        const favQ = query(favoritesRef, where('user_id', '==', currentUser.uid));
        const favoritesSnapshot = await getDocs(favQ);
        favoritesSet = new Set(favoritesSnapshot.docs.map((doc) => doc.data().message_id));
      } catch (e) {
        console.error('Error loading favorites:', e);
      }
    }

    // Получаем закреплённые сообщения
    let pinnedSet = new Set<string>();
    try {
      const pinnedRef = collection(db, 'pinned_messages');
      const pinnedQ = query(pinnedRef, where('chat_id', '==', chatId));
      const pinnedSnapshot = await getDocs(pinnedQ);
      pinnedSet = new Set(pinnedSnapshot.docs.map((doc) => doc.data().message_id));
    } catch (e) {
      console.error('Error loading pinned:', e);
    }

    // Преобразуем в Message[]
    return messagesData.map((msg: any) => ({
      id: msg.id,
      sender: msg.user_id,
      senderName: usersMap.get(msg.user_id) || 'Unknown',
      text: msg.content,
      timestamp: msg.created_at?.toMillis?.() || Date.now(),
      type: msg.message_type || 'text',
      photoUrl: msg.media_url,
      voiceData:
        msg.message_type === 'voice'
          ? { duration: 0, url: msg.media_url }
          : undefined,
      isFavorite: favoritesSet.has(msg.id),
      isPinned: pinnedSet.has(msg.id),
    }));
  } catch (error: any) {
    console.error('Get messages error:', error);
    throw new Error(error.message || 'Ошибка загрузки сообщений');
  }
};

export const listenToMessages = (
  chatId: string,
  callback: (messages: Message[]) => void
) => {
  const messagesRef = collection(db, 'messages');
  const q = query(messagesRef, where('chat_id', '==', chatId), orderBy('created_at', 'asc'));
  
  const unsubscribe = onSnapshot(q, async (querySnapshot) => {
    try {
      const messagesData = querySnapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));

      if (messagesData.length === 0) {
        callback([]);
        return;
      }

      // Получаем информацию об авторах
      const userIds = [...new Set(messagesData.map((m: any) => m.user_id))];
      const usersMap = new Map<string, string>();

      for (const userId of userIds) {
        try {
          const userDoc = await getDoc(doc(db, 'users', userId));
          if (userDoc.exists()) {
            usersMap.set(userId, userDoc.data().username);
          }
        } catch (e) {
          usersMap.set(userId, 'Unknown');
        }
      }

      // Преобразуем в Message[]
      const messages = messagesData.map((msg: any) => ({
        id: msg.id,
        sender: msg.user_id,
        senderName: usersMap.get(msg.user_id) || 'Unknown',
        text: msg.content,
        timestamp: msg.created_at?.toMillis?.() || Date.now(),
        type: msg.message_type || 'text',
        photoUrl: msg.media_url,
        voiceData:
          msg.message_type === 'voice'
            ? { duration: 0, url: msg.media_url }
            : undefined,
      }));

      callback(messages);
    } catch (error) {
      console.error('Error processing messages:', error);
    }
  }, (error) => {
    console.error('Listener error:', error);
  });

  return unsubscribe;
};

