export const getUserChats = async (userId: string): Promise<Chat[]> => {
  try {
    const membersRef = collection(db, 'chat_members');
    const q = query(membersRef, where('user_id', '==', userId));
    const membersSnapshot = await getDocs(q);

    const chats: Chat[] = [];

    for (const memberDoc of membersSnapshot.docs) {
      const chatData = await getDoc(doc(db, 'chats', memberDoc.data().chat_id));
      if (chatData.exists()) {
        const data = chatData.data();
        chats.push({
          id: chatData.id,
          name: data.name,
          type: data.type || (data.is_group ? 'group' : 'private'),
          createdAt: data.created_at?.toMillis?.() || Date.now(),
          members: data.members || [],
          messages: [],
        });
      }
    }

    return chats;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const searchUser = async (searchQuery: string) => {
  try {
    const usersRef = collection(db, 'users');
    const q = query(usersRef, where('username', '>=', searchQuery), where('username', '<=', searchQuery + '\uf8ff'));
    const querySnapshot = await getDocs(q);

    if (!querySnapshot.empty) {
      const user = querySnapshot.docs[0].data();
      return {
        id: querySnapshot.docs[0].id,
        username: user.username,
        userId: user.userId,
        avatarUrl: user.avatar_url,
      };
    }

    return null;
  } catch (error: any) {
    console.error('Search user error:', error);
    return null;
  }
};

export const createPrivateChat = async (
  userId: string,
  otherUserId: string,
  otherUserName: string
): Promise<Chat> => {
  try {
    // Проверяем существующий чат между этими двумя пользователями
    const chatsRef = collection(db, 'chats');
    const q = query(chatsRef, where('is_group', '==', false));
    const chatsSnapshot = await getDocs(q);

    for (const chatDoc of chatsSnapshot.docs) {
      const membersRef = collection(db, 'chat_members');
      const membersQ = query(membersRef, where('chat_id', '==', chatDoc.id));
      const membersSnapshot = await getDocs(membersQ);

      const memberIds = membersSnapshot.docs.map((doc) => doc.data().user_id);
      if (memberIds.includes(userId) && memberIds.includes(otherUserId)) {
        const chatData = chatDoc.data();
        return {
          id: chatDoc.id,
          name: otherUserName,
          type: 'private',
          createdAt: chatData.created_at?.toMillis?.() || Date.now(),
          members: memberIds,
          messages: [],
        };
      }
    }

    // Создаём новый чат
    const newChatRef = await addDoc(collection(db, 'chats'), {
      name: otherUserName,
      is_group: false,
      type: 'private',
      created_at: Timestamp.now(),
      members: [userId, otherUserId],
    });

    // Добавляем членов
    await addDoc(collection(db, 'chat_members'), {
      chat_id: newChatRef.id,
      user_id: userId,
    });

    await addDoc(collection(db, 'chat_members'), {
      chat_id: newChatRef.id,
      user_id: otherUserId,
    });

    return {
      id: newChatRef.id,
      name: otherUserName,
      type: 'private',
      createdAt: Date.now(),
      members: [userId, otherUserId],
      messages: [],
    };
  } catch (error: any) {
    console.error('Create private chat error:', error);
    throw new Error(error.message);
  }
};

