export const getFavoriteMessages = async (
  userId: string,
  chatId: string
): Promise<Message[]> => {
  try {
    const favoritesRef = collection(db, 'favorites');
    const favQ = query(favoritesRef, where('user_id', '==', userId));
    const favoritesSnapshot = await getDocs(favQ);

    if (favoritesSnapshot.empty) return [];

    const messageIds = favoritesSnapshot.docs.map((doc) => doc.data().message_id);

    const messagesRef = collection(db, 'messages');
    const messagesQ = query(messagesRef, where('chat_id', '==', chatId), orderBy('created_at', 'asc'));
    const messagesSnapshot = await getDocs(messagesQ);

    const filteredMessages = messagesSnapshot.docs
      .filter((doc) => messageIds.includes(doc.id))
      .map((doc) => ({ id: doc.id, ...doc.data() }));

    // Получаем информацию об авторах
    const userIds = [...new Set(filteredMessages.map((m: any) => m.user_id))];
    const usersMap = new Map<string, string>();

    for (const userId of userIds) {
      const userDoc = await getDoc(doc(db, 'users', userId));
      if (userDoc.exists()) {
        usersMap.set(userId, userDoc.data().username);
      }
    }

    return filteredMessages.map((msg: any) => ({
      id: msg.id,
      sender: msg.user_id,
      senderName: usersMap.get(msg.user_id) || 'Unknown',
      text: msg.content,
      timestamp: msg.created_at?.toMillis?.() || Date.now(),
      type: msg.message_type || 'text',
      photoUrl: msg.media_url,
      isFavorite: true,
    }));
  } catch (error: any) {
    console.error('Get favorite messages error:', error);
    throw new Error(error.message || 'Ошибка загрузки избранных');
  }
};

