export const createGroup = async (
  groupName: string,
  creatorId: string,
  members: string[]
) => {
  try {
    const chatRef = await addDoc(collection(db, 'chats'), {
      name: groupName,
      is_group: true,
      type: 'group',
      created_at: Timestamp.now(),
      members: [creatorId, ...members],
    });

    for (const userId of [creatorId, ...members]) {
      await addDoc(collection(db, 'chat_members'), {
        chat_id: chatRef.id,
        user_id: userId,
      });
    }

    return {
      id: chatRef.id,
      name: groupName,
      type: 'group',
      createdAt: Date.now(),
      members: [creatorId, ...members],
    };
  } catch (error: any) {
    throw new Error(error.message);
  }
};

